mapper.select:
/* com.erns.coching.raw.mapper.RawDAO.getDetail */
SELECT

FROM  T_RAW_DETAIL FF
INNER JOIN T_RAW_MANAGER EE
    ON EE.RAW_SEQ = FF.RAW_SEQ AND EE.MEMB_SEQ = FF.MEMB_SEQ
INNER JOIN T_RAW_MST AA
	ON AA.RAW_SEQ = FF.RAW_SEQ

	AND FF.DEL_YN = 'N'
	AND FF.RAW_SEQ 	= #{rawSeq	, jdbcType=INTEGER}
	AND FF.MEMB_SEQ = #{membSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.getDetail */ SELECT
FROM T_RAW_DETAIL FF INNER JOIN T_RAW_MANAGER EE ON EE.RAW_SEQ = FF.RAW_SEQ AND EE.MEMB_SEQ = FF.MEMB_SEQ INNER JOIN T_RAW_MST AA ON AA.RAW_SEQ = FF.RAW_SEQ
AND FF.RAW_DETAIL_SEQ = #{rawDetailSeq, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.raw.mapper.RawDAO.detailInsert */


	SELECT nextval('seq_t_raw_detail')


INSERT INTO T_RAW_DETAIL (
	RAW_DETAIL_SEQ,
	RAW_SEQ,
	MEMB_SEQ,
	TITLE,
	HASHTAG,
	FILE_ID,
	RAW_DESC,
	RAW_DETAIL,
	RAW_DETAIL_TEXT,
	PERMIT_YN,
	USE_YN,
	DEL_YN,
	RGTR,
	RGT_DTTM
)
VALUES (
	#{rawDetailSeq		, jdbcType=INTEGER}
	, #{rawSeq			, jdbcType=INTEGER}
	, #{membSeq			, jdbcType=INTEGER}
	, #{title			, jdbcType=VARCHAR}
	, #{hashtag			, jdbcType=VARCHAR}
	, #{fileId			, jdbcType=VARCHAR}
	, #{rawDesc			, jdbcType=VARCHAR}
	, #{rawDetail		, jdbcType=VARCHAR}
  	, regexp_replace(regexp_replace(regexp_replace(#{rawDetail		, jdbcType=VARCHAR}, '<img[^>]*>', '', 'g'), E'<(.|\\n)*?>', '', 'g'), '\\s+', ' ', 'g')
	, COALESCE(#{permitYn	, jdbcType=VARCHAR}, 'Y')
	, COALESCE(#{useYn		, jdbcType=VARCHAR}, 'N')
	, COALESCE(#{delYn		, jdbcType=VARCHAR}, 'N')
	, #{rgtr			, jdbcType=INTEGER}
	, now()
)
ON CONFLICT (RAW_SEQ, MEMB_SEQ)
DO UPDATE
	SET
		TITLE = 		#{title			, jdbcType=VARCHAR}
		, HASHTAG = 	#{hashtag		, jdbcType=VARCHAR}
		, FILE_ID = 	#{fileId		, jdbcType=VARCHAR}
		, RAW_DESC = 	#{rawDesc		, jdbcType=VARCHAR}
		, RAW_DETAIL = 	#{rawDetail		, jdbcType=VARCHAR}
		, RAW_DETAIL_TEXT = regexp_replace(regexp_replace(regexp_replace(#{rawDetail		, jdbcType=VARCHAR}, '<img[^>]*>', '', 'g'), E'<(.|\\n)*?>', '', 'g'), '\\s+', ' ', 'g')
    	, USE_YN = 		COALESCE(#{useYn		, jdbcType=VARCHAR}, 'N')
    	, DEL_YN = 		COALESCE(#{delYn		, jdbcType=VARCHAR}, 'N')
		, CHNR = 		#{chnr			, jdbcType=INTEGER}
		, CHNG_DTTM = 	now()

