UPDATE T_RAW_DETAIL SET
PERMIT_YN            = COALESCE(#{permitYn	, jdbcType=CHAR}, 'N')

, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
, CHNG_DTTM  		= now()

	AND RAW_DETAIL_SEQ 		= #{rawDetailSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.updateDetailUseYn */

UPDATE T_RAW_DETAIL SET
USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')

, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
, CHNG_DTTM  		= now()

	AND RAW_DETAIL_SEQ 		= #{rawDetailSeq	, jdbcType=INTEGER}

/* com.erns.coching.raw.mapper.RawDAO.updateDetailDelYn */

UPDATE T_RAW_DETAIL SET
DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
, DLTR 		 		= #{dltr	, jdbcType=INTEGER}
, DLT_DTTM  		= now()

	AND RAW_DETAIL_SEQ 		= #{rawDetailSeq	, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.raw.mapper.RawDAO.getGarbageList */

SELECT B.* FROM (
	SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
		SELECT

		FROM  T_RAW_MST AA
		INNER JOIN T_MEMB_INF MI
			ON AA.RGTR = MI.MEMB_SEQ



		order by AA.CHNG_DTTM desc
	) A
) B

	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.raw.mapper.RawDAO.getCmTypeList */ SELECT GRP_CODE, CODE, CODE_NM_KO, CODE_NM_EN, INPT_TYPE, SORT_ORD FROM T_CM_RAW_TYPE
AND USE_YN = 'Y'
ORDER BY GRP_CODE, CODE, SORT_ORD ASC

/* com.erns.coching.raw.mapper.RawDAO.getIngdDic */ SELECT ID AS id, REP_NAME AS repName, REP_NAME_EN AS repNameEn FROM T_INGD_DIC
AND ID = #{id, jdbcType=INTEGER}
AND UPPER(REP_NAME) = UPPER(#{repName, jdbcType=VARCHAR})
AND UPPER(REP_NAME_EN) = UPPER(#{repNameEn, jdbcType=VARCHAR})
ORDER BY ID ASC
